func acctFmt(stats *dto.AccountingDashboardStats, kind string) string {
	if stats == nil {
		return "0.00"
	}
	switch kind {
	case "cash":
		return fmt.Sprintf("%.2f", stats.CashBalance)
	case "bank":
		return fmt.Sprintf("%.2f", stats.BankBalance)
	case "income":
		return fmt.Sprintf("%.2f", stats.MonthlyIncome)
	case "expense":
		return fmt.Sprintf("%.2f", stats.MonthlyExpense)
	}
	return "0.00"
}

